SELECT object_id, vegetation_count 
FROM land_data
WHERE state_id IN (SELECT state_id FROM states WHERE country = 'USA');

SELECT object_id, vegetation_count
FROM land_data
WHERE vegetation_count > (SELECT AVG(vegetation_count) FROM land_data);

SELECT ld.object_id, ld.state_id, vt.vegetation_name AS majority_vegetation
FROM land_data ld
INNER JOIN vegetation_types vt ON ld.majority = vt.vegetation_id;
